public static long solve(long[] nums) {
    int n = nums.length;
    int totalStates = 1;
    for (int i = 0; i < n; i++) {
        totalStates *= 3;
    }
    long max = 0;
    for (int state = 0; state < totalStates; state++) {
        long xorA = 0;
        long andB = -1;
        long xorC = 0;
        int s = state;
        for (int i = 0; i < n; i++) {
            int group = s % 3;
            s /= 3;
            if (group == 0) {
                xorA ^= nums[i];
            } else if (group == 1) {
                if (andB == -1) {
                    andB = nums[i];
                } else {
                    andB &= nums[i];
                }
            } else {
                xorC ^= nums[i];
            }
        }
        if (andB == -1) {
            andB = 0;
        }
        long total = xorA + andB + xorC;
        if (total > max) {
            max = total;
        }
    }
    return max;
}
```

