public static long solve(long[] nums) {
    int n = nums.length;
    int full_mask = (1 << n) - 1;
    long totalXOR = 0;
    for (long num : nums) {
        totalXOR ^= num;
    }

    long[] andMask = new long[1 << n];
    andMask[0] = -1;
    for (int mask = 1; mask < (1 << n); mask++) {
        int i = Integer.numberOfTrailingZeros(mask);
        andMask[mask] = andMask[mask & ~(1 << i)] & nums[i];
    }

    long[] xorMask = new long[1 << n];
    xorMask[0] = 0;
    for (int mask = 1; mask < (1 << n); mask++) {
        int i = Integer.numberOfTrailingZeros(mask);
        xorMask[mask] = xorMask[mask & ~(1 << i)] ^ nums[i];
    }

    long best = Long.MIN_VALUE;
    for (int maskB = 0; maskB < (1 << n); maskB++) {
        long andB_val = (maskB == 0) ? 0 : andMask[maskB];
        long xorB = xorMask[maskB];
        int rem = full_mask ^ maskB;
        long xorC_empty = totalXOR ^ 0 ^ xorB;
        long candidate_empty = 0 + andB_val + xorC_empty;
        if (candidate_empty > best) {
            best = candidate_empty;
        }

        if (rem != 0) {
            int maskA = rem;
            do {
                long xorA = xorMask[maskA];
                long xorC = totalXOR ^ xorA ^ xorB;
                long candidate = xorA + andB_val + xorC;
                if (candidate > best) {
                    best = candidate;
                }
                if (maskA == 0) break;
                maskA = (maskA - 1) & rem;
            } while (true);
        }
    }
    return best;
}
```

