public static long solve(long[] nums) {
    int n = nums.length;
    if (n == 0) return 0;
    int fullMask = (1 << n) - 1;
    long[] totalXOR = new long[fullMask + 1];
    for (int mask = 0; mask <= fullMask; mask++) {
        long xor = 0;
        for (int i = 0; i < n; i++) {
            if ((mask & (1 << i)) != 0) {
                xor ^= nums[i];
            }
        }
        totalXOR[mask] = xor;
    }

    long[] best = new long[fullMask + 1];
    for (int T = 0; T <= fullMask; T++) {
        List<Integer> indices = new ArrayList<>();
        for (int i = 0; i < n; i++) {
            if ((T & (1 << i)) != 0) {
                indices.add(i);
            }
        }
        int k = indices.size();
        if (k == 0) {
            best[T] = 0;
            continue;
        }
        long[] arr = new long[k];
        for (int i = 0; i < k; i++) {
            arr[i] = nums[indices.get(i)];
        }
        int numSub = 1 << k;
        long[] dpXor = new long[numSub];
        dpXor[0] = 0;
        for (int mask = 1; mask < numSub; mask++) {
            int j = Integer.numberOfTrailingZeros(mask);
            int prevMask = mask ^ (1 << j);
            dpXor[mask] = dpXor[prevMask] ^ arr[j];
        }
        long totalVal = totalXOR[T];
        long currentBest = 0;
        for (int mask = 0; mask < numSub; mask++) {
            long a = dpXor[mask];
            long val = a + (a ^ totalVal);
            if (val > currentBest) {
                currentBest = val;
            }
        }
        best[T] = currentBest;
    }

    long[] andVal = new long[fullMask + 1];
    andVal[0] = -1;
    for (int mask = 1; mask <= fullMask; mask++) {
        int j = Integer.numberOfTrailingZeros(mask);
        int maskWithout = mask ^ (1 << j);
        andVal[mask] = andVal[maskWithout] & nums[j];
    }
    andVal[0] = 0;

    long maxAns = 0;
    for (int B = 0; B <= fullMask; B++) {
        int T = fullMask ^ B;
        long candidate = andVal[B] + best[T];
        if (candidate > maxAns) {
            maxAns = candidate;
        }
    }

    return maxAns;
}
```

